43	///////////////////////////////////////////////////////////////////////////////
44	
45	// Users are not supposed to use this class directly.
46	// This is a CRTP base class for the actual tile schedulers.
47	template<class Subclass>
48	class StaticPersistentTileScheduler {
49	
50	private:
51	  uint64_t current_work_linear_idx_;
52	  uint64_t total_grid_size_;
53	
54	public:
55	  struct WorkTileInfo {
56	    int32_t M_idx = 0;
57	    int32_t N_idx = 0;
58	    int32_t L_idx = 0;
59	    bool is_valid_tile = false;
60	
61	    CUTLASS_HOST_DEVICE
62	    bool
63	    is_valid() const {
64	      return is_valid_tile;
65	    }
66	
67	    CUTLASS_HOST_DEVICE
68	    static WorkTileInfo
69	    invalid_work_tile() {
70	      return {-1, -1, -1, false};
71	    }
72	
73	    CUTLASS_HOST_DEVICE
74	    bool
75	    is_final_split(uint32_t k_tiles_per_output_tile) const {
76	      return true;
77	    }
78	
79	    CUTLASS_HOST_DEVICE
80	    int32_t
81	    reduction_subtile_idx() const {
82	      return -1;
83	    }
84	  };
85	
86	  using Params = PersistentTileSchedulerSm90Params;
87	  using RasterOrder = typename Params::RasterOrder;
88	  using RasterOrderOptions = typename Params::RasterOrderOptions;
89	  static constexpr bool IsDynamicPersistent = false;
90	
91	public:
92	  struct Arguments {
93	    int max_swizzle_size = 1;
94	    RasterOrderOptions raster_order = RasterOrderOptions::Heuristic;
95	  };
96	
97	  template <class ProblemShapeMNKL, class TileShape, class ClusterShape>
98	  static Params
99	  to_underlying_arguments(
100	      ProblemShapeMNKL problem_shape_mnkl,
101	      TileShape tile_shape,
102	      ClusterShape cluster_shape,
103	      [[maybe_unused]] KernelHardwareInfo const& hw_info,
104	      Arguments const& arguments,
105	      [[maybe_unused]] void* workspace=nullptr,
106	      [[maybe_unused]] const uint32_t epilogue_subtile = 1,
107	      [[maybe_unused]] uint32_t ktile_start_alignment_count = 1u) {
108	
109	    // We only need the tile and cluster shape during scheduler setup, so let FTAD do the magic
110	    static_assert(cute::is_static<TileShape>::value);
111	    static_assert(cute::is_static<ClusterShape>::value);
112	
113	    dim3 problem_blocks = get_tiled_cta_shape_mnl(problem_shape_mnkl, tile_shape, cluster_shape);
114	
115	    Params params;
116	    params.initialize(
117	      problem_blocks,
118	      to_gemm_coord(cluster_shape),
119	      hw_info,
120	      arguments.max_swizzle_size,
121	      arguments.raster_order
122	    );
123	
124	    return params;
125	  }
126	
127	  CUTLASS_HOST_DEVICE
128	  static bool
129	  can_implement(Arguments const& args, KernelHardwareInfo const&) {
130	    return args.max_swizzle_size >= 0;
131	  }
132	
133	  CUTLASS_HOST_DEVICE
134	  StaticPersistentTileScheduler() { }
135	
136	  CUTLASS_DEVICE explicit StaticPersistentTileScheduler(Params const& params_) : scheduler_params(params_) {
137	    // MSVC requires protecting use of CUDA-specific nonstandard syntax,
138	    // like blockIdx and gridDim, with __CUDA_ARCH__.
139	#if defined(__CUDA_ARCH__)
140	    if (params_.raster_order_ == RasterOrder::AlongN) {
141	      current_work_linear_idx_ = uint64_t(blockIdx.x) + uint64_t(blockIdx.y) * uint64_t(gridDim.x);
142	    }
143	    else {
144	      current_work_linear_idx_ = uint64_t(blockIdx.x) * uint64_t(gridDim.y) + uint64_t(blockIdx.y);
145	    }
146	
147	    total_grid_size_ = uint64_t(gridDim.x) * uint64_t(gridDim.y) * uint64_t(gridDim.z);
148	#else
149	    CUTLASS_ASSERT(false && "This line should never be reached");
150	#endif
151	  }
152	
153	  // Returns the initial work tile info that will be computed over
154	  template <class ClusterShape>
155	  CUTLASS_DEVICE
156	  WorkTileInfo
157	  initial_work_tile_info(ClusterShape cluster_shape) {
158	    return get_current_work();
159	  }
160	
161	  CUTLASS_DEVICE
162	  WorkTileInfo
163	  get_current_work() const {
164	    return get_current_work_for_linear_idx(current_work_linear_idx_);
165	  }
166	
167	  CUTLASS_DEVICE
168	  WorkTileInfo
169	  get_current_work_for_linear_idx(uint64_t linear_idx) const {
170	    if (linear_idx >= scheduler_params.blocks_per_problem_) {
171	      return WorkTileInfo::invalid_work_tile();
172	    }
173	
174	    // Map worker's linear index into the CTA tiled problem shape to the corresponding MNL indices
175	    uint64_t work_idx_l, remainder;
176	    scheduler_params.divmod_batch_(work_idx_l, remainder, linear_idx);
177	
178	    uint64_t blk_per_grid_dim = scheduler_params.divmod_cluster_shape_minor_.divide(remainder);
179	
180	    auto [work_idx_m, work_idx_n] = Subclass::get_work_idx_m_and_n(blk_per_grid_dim,
181	                                                         scheduler_params.divmod_cluster_shape_major_,
182	                                                         scheduler_params.divmod_cluster_shape_minor_,
183	                                                         scheduler_params.divmod_cluster_blk_major_,
184	                                                         scheduler_params.log_swizzle_size_,
185	                                                         scheduler_params.raster_order_);
186	
187	    return {work_idx_m, work_idx_n, static_cast<int32_t>(work_idx_l), true};
188	  }
189	
190	  CUTLASS_DEVICE
191	  void
192	  advance_to_next_work(uint32_t advance_count = 1) {
193	    current_work_linear_idx_ += total_grid_size_ * uint64_t(advance_count);
194	  }
195	
196	  CUTLASS_DEVICE
197	  bool is_last_tile(WorkTileInfo& work_tile_info, uint32_t advance_count = 1) const {
198	    if (continue_current_work(work_tile_info)) {
199	      return false;
200	    }
201	    return not get_current_work_for_linear_idx(
202	        current_work_linear_idx_ + (total_grid_size_ * uint64_t(advance_count))
203	    ).is_valid();
204	  }
205	
206	  // Computes the linear index within a batch given M and N tile offsets within the batch.
207	  // This essentially inverts the mapping performed in get_work_idx_m_and_n
208	  static CUTLASS_DEVICE
209	  uint64_t
210	  get_linear_idx_from_m_and_n(
211	    int32_t tile_m,
212	    int32_t tile_n,
213	    FastDivmodU64Pow2 const& divmod_cluster_shape_major,
214	    FastDivmodU64Pow2 const& divmod_cluster_shape_minor,
215	    FastDivmodU64 const& divmod_cluster_blk_major,
216	    int32_t log_swizzle_size,
217	    RasterOrder raster_order) {
218	
219	    uint64_t minor_work_idx, major_work_idx, cluster_minor_offset;
220	    if (raster_order == RasterOrder::AlongN) {
221	      minor_work_idx = static_cast<uint64_t>(tile_m);
222	      major_work_idx = static_cast<uint64_t>(tile_n);
223	      uint64_t cluster_m = divmod_cluster_shape_minor.divide(tile_m) * divmod_cluster_shape_minor.divisor;
224	      cluster_minor_offset = tile_m - cluster_m;
225	    }
226	    else {
227	      major_work_idx = static_cast<uint64_t>(tile_m);
228	      minor_work_idx = static_cast<uint64_t>(tile_n);
229	      uint64_t cluster_n = divmod_cluster_shape_minor.divide(tile_n) * divmod_cluster_shape_minor.divisor;
230	      cluster_minor_offset = tile_n - cluster_n;
231	    }
232	
233	    uint64_t cluster_idx_minor, cluster_idx_major, cluster_major_offset;
234	    cluster_idx_minor = divmod_cluster_shape_minor.divide(minor_work_idx - cluster_minor_offset);
235	    divmod_cluster_shape_major(cluster_idx_major, cluster_major_offset, major_work_idx);
236	
237	    uint64_t cluster_idx_minor_div_swizzle = cluster_idx_minor >> log_swizzle_size;
238	    uint64_t offset = cluster_idx_minor & ((1 << log_swizzle_size) - 1);
239	
240	    uint64_t extra = cluster_idx_minor_div_swizzle * divmod_cluster_blk_major.divisor + cluster_idx_major;
241	
242	    uint64_t cluster_id = (extra << log_swizzle_size) | offset;
243	    return (cluster_id * divmod_cluster_shape_major.divisor + cluster_major_offset) * divmod_cluster_shape_minor.divisor + cluster_minor_offset;
244	  }
245	
246	  // Given the inputs, computes the total number of output blocks over which this problem will compute. 
247	  // Note that this is only the logical size of our grid, not the physical grid we will actually launch.
248	  template<class ProblemShapeMNKL, class BlockShape, class ClusterShape>
249	  CUTLASS_HOST_DEVICE static
250	  dim3
251	  get_tiled_cta_shape_mnl(ProblemShapeMNKL problem_shape_mnkl, BlockShape cta_shape, ClusterShape cluster_shape) {
252	    auto cta_m = cute::size(cute::ceil_div(cute::shape<0>(problem_shape_mnkl), cute::shape<0>(cta_shape)));
253	    auto cta_n = cute::size(cute::ceil_div(cute::shape<1>(problem_shape_mnkl), cute::shape<1>(cta_shape)));
254	
255	    return Params::get_tiled_cta_shape_mnl(
256	      to_gemm_coord(problem_shape_mnkl),
257	      to_gemm_coord(cluster_shape),
258	      cta_m, cta_n
259	    );
260	  }
261	
262	  // Reloaded interface that receives WorkTileInfo to deduce next work.
263	  // Kernel helper function to get next work tile
264	  CUTLASS_DEVICE
265	  auto
266	  fetch_next_work(WorkTileInfo work_tile_info) {
267	    if (continue_current_work(work_tile_info)) {
268	      return cute::make_tuple(work_tile_info, true);
269	    }
270	
271	    advance_to_next_work();
272	    return cute::make_tuple(get_current_work(), true);
273	  }
274	  
275	  // Given the inputs, computes the total number of output blocks over which this problem will compute.
276	  // Note that this is only the logical size of our grid, not the physical grid we will actually launch.
277	  template<class ProblemShapeMNKL, class TileShape, class AtomThrShape, class ClusterShape>
278	  CUTLASS_HOST_DEVICE static
279	  dim3
280	  get_tiled_cta_shape_mnl(ProblemShapeMNKL problem_shape_mnkl,
281	                          TileShape tile_shape_mnk,
282	                          AtomThrShape atom_thr_shape_mnk,
283	                          ClusterShape cluster_shape_mnk) {
284	    auto [tiles_m, tiles_n, tiles_l] = product_each(ceil_div(select<0,1,3>(problem_shape_mnkl), take<0,2>(tile_shape_mnk)));
285	    auto cta_m = round_nearest(tiles_m * size<0>(atom_thr_shape_mnk), size<0>(cluster_shape_mnk));
286	    auto cta_n = round_nearest(tiles_n * size<1>(atom_thr_shape_mnk), size<1>(cluster_shape_mnk));
287	
288	    return Params::get_tiled_cta_shape_mnl(
289	      to_gemm_coord(problem_shape_mnkl),
290	      to_gemm_coord(cluster_shape_mnk),
291	      cta_m, cta_n
292	    );
293	  }
294	
295	  // Kernel helper function to get next work tile
296	  template <class TileSchedulerPipeline, class TileSchedulerPipelineState>
297	  CUTLASS_DEVICE
298	  auto
299	  fetch_next_work(
300	      WorkTileInfo work_tile_info,
301	      TileSchedulerPipeline& scheduler_pipeline,
302	      TileSchedulerPipelineState scheduler_pipe_consumer_state) {
303	    return fetch_next_work(work_tile_info);
304	  }
