306	  CUTLASS_DEVICE
307	  static auto
308	  work_tile_to_cta_coord(WorkTileInfo work_tile_info) {
309	    // Get every cta coord in three dimensions of the cluster
310	    auto [cta_m_in_cluster, cta_n_in_cluster, cta_l_in_cluster] = cute::block_id_in_cluster();
311	    return make_coord(
312	      work_tile_info.M_idx + static_cast<int32_t>(cta_m_in_cluster),
313	      work_tile_info.N_idx + static_cast<int32_t>(cta_n_in_cluster),
314	      _,
315	      work_tile_info.L_idx + static_cast<int32_t>(cta_l_in_cluster)
316	    );
317	  }
318	
319	  CUTLASS_DEVICE
320	  static auto
321	  work_tile_to_cta_coord(WorkTileInfo work_tile_info, dim3 block_id_in_cluster) {
322	    // Get every cta coord in three dimensions of the cluster
323	    auto [cta_m_in_cluster, cta_n_in_cluster, cta_l_in_cluster] = block_id_in_cluster;
324	    return make_coord(
325	      work_tile_info.M_idx + static_cast<int32_t>(cta_m_in_cluster),
326	      work_tile_info.N_idx + static_cast<int32_t>(cta_n_in_cluster),
327	      _,
328	      work_tile_info.L_idx + static_cast<int32_t>(cta_l_in_cluster)
329	    );
330	  }
331	
332	  // Given the inputs, computes the physical grid we should launch.
333	  template<class ProblemShapeMNKL, class BlockShape, class ClusterShape>
334	  CUTLASS_HOST_DEVICE static
335	  dim3
336	  get_grid_shape(
337	      [[maybe_unused]] Params const& params,
338	      ProblemShapeMNKL problem_shape_mnk,
339	      BlockShape cta_shape,
340	      ClusterShape cluster_shape,
341	      KernelHardwareInfo hw_info,
342	      Arguments arguments = Arguments{},
343	      bool truncate_by_problem_size=true) {
344	
345	    auto problem_shape_mnkl = cute::append<4>(problem_shape_mnk, cute::Int<1>{});
346	    dim3 problem_blocks = get_tiled_cta_shape_mnl(problem_shape_mnkl, cta_shape, cluster_shape);
347	
348	    return Params::get_grid_shape(
349	      problem_blocks,
350	      to_gemm_coord(cluster_shape),
351	      hw_info,
352	      arguments.max_swizzle_size,
353	      arguments.raster_order,
354	      /* truncate_by_problem_size = */true
355	    );
356	  }
357	
358	  // Given the inputs, computes the physical grid we should launch.
359	  template<class ProblemShapeMNKL, class TileShape, class AtomThrShape, class ClusterShape>
360	  static dim3
361	  get_grid_shape(
362	      Params const& params,
363	      ProblemShapeMNKL problem_shape_mnkl,
364	      TileShape tile_shape_mnk,
365	      AtomThrShape atom_thr_shape_mnk,
366	      ClusterShape cluster_shape_mnk,
367	      KernelHardwareInfo hw_info) {
368	
369	    dim3 problem_blocks = get_tiled_cta_shape_mnl(problem_shape_mnkl, tile_shape_mnk, atom_thr_shape_mnk, cluster_shape_mnk);
370	    Arguments args{};
371	    if constexpr (!std::is_const_v<decltype(args.max_swizzle_size)>) {
372	      args.max_swizzle_size = 1 << params.log_swizzle_size_;
373	    }
374	    args.raster_order = params.raster_order_ == RasterOrder::AlongN ? RasterOrderOptions::AlongN : RasterOrderOptions::AlongM;
375	
376	    return Params::get_grid_shape(
377	      problem_blocks,
378	      to_gemm_coord(cluster_shape_mnk),
379	      hw_info,
380	      args.max_swizzle_size,
381	      args.raster_order,
382	      /* truncate_by_problem_size = */true
383	    );
384	  }
