460	    // Reductions use BlockStripedReduce with a width of BarrierManager::ThreadCount under the hood.
461	    // Thus, the start of the reduction space is the same across all threads in a warp group.
462	    uint64_t reduction_offset_base = (static_cast<uint64_t>(cute::size<0>(TileShape{})) * static_cast<uint64_t>(cute::size<1>(TileShape{})) * reduction_tile_idx * num_accumulator_mtxs) +
463	      (static_cast<uint64_t>(size(accumulators)) * barrier_idx * BarrierManager::ThreadCount * num_accumulator_mtxs)
464	      + static_cast<uint64_t>(size(accumulators)) * BarrierManager::ThreadCount * idx_accumulator_mtxs;
465	    uint64_t reduction_offset = reduction_offset_base + reduction_peer_offset;
466	
467	    ElementAccumulator* group_reduction_workspace = reinterpret_cast<ElementAccumulator*>(params.reduction_workspace_) + reduction_offset;
468	
469	    using AccumulatorArrayT = Array<typename FrgTensorC::value_type, size(FrgTensorC{})>;
470	    using BlockStripedReduceT = BlockStripedReduce<BarrierManager::ThreadCount, AccumulatorArrayT>;
471	
472	    AccumulatorArrayT* reduction_workspace_array = reinterpret_cast<AccumulatorArrayT*>(group_reduction_workspace);
473	    AccumulatorArrayT* accumulator_array = reinterpret_cast<AccumulatorArrayT*>(accumulators.data());
474	
475	    uint32_t barrier_group_thread_idx = threadIdx.x % BarrierManager::ThreadCount;
476	
477	    // The number of tiles for which reduction is required is either:
478	    //   (a) the total number of output tiles (in the case of split-K)
479	    //   (b) the number of stream-K tiles (potentially multiplied by peer count if using separate reduction)
480	    // To calculate the total number of output tiles in the split-K case, we
481	    // note that, in the split-K case, the units_per_problem_ member of Params will be
482	    // the total number of output tiles.
483	    uint32_t reduction_tiles = 0;
484	    if (params.divmod_splits_.divisor > 1) {
485	      reduction_tiles = params.units_per_problem_;
486	    }
487	    else if (
488	      params.requires_separate_reduction()
489	      ) {
490	      reduction_tiles = params.sk_tiles_ * Params::max_peers_per_tile(params.sk_units_, params.sk_tiles_);
491	    }
492	    else {
493	      reduction_tiles = params.sk_tiles_;
494	    }
495	
496	    uint64_t reduction_workspace_size = Params::get_reduction_workspace_size(
497	      reduction_tiles, to_gemm_coord(TileShape{}), sizeof_bits<ElementAccumulator>::value, num_accumulator_mtxs);
498	    BarrierType* lock_workspace = reinterpret_cast<BarrierType*>(
499	      reinterpret_cast<uint8_t*>(params.reduction_workspace_) + reduction_workspace_size);
500	
501	    if (work_tile_info.is_reduction_unit()) {
502	      // Wait until the peers collaborating on this output tile have all written
503	      // their accumulators to workspace.
504	      BarrierManager::wait_eq(barrier_idx, lock_workspace, barrier_group_thread_idx, lock_idx, num_peers);
505	
506	      separate_reduction<FrgTensorC, BarrierManager>(accumulators, num_barriers, group_reduction_workspace, barrier_group_thread_idx, num_peers, num_accumulator_mtxs);
507	    }
508	    else if (!compute_epilogue(work_tile_info, params)) {
509	      if (
510	        params.requires_separate_reduction()
511	        || work_tile_info.K_idx == 0
512	        ) {
513	        // The first peer initializes the workspace partials in the non-separate-reduction case,
514	        // and all peers write to their own location in workspace when using separate reduction
515	        BlockStripedReduceT::store(reduction_workspace_array, *accumulator_array, barrier_group_thread_idx);
516	      }
517	      else {
518	        if (params.reduction_mode_ == ReductionMode::Deterministic) {
519	          // Wait until the preceding split added its accumulators
520	          BarrierManager::wait_eq(barrier_idx, lock_workspace, barrier_group_thread_idx, lock_idx, work_tile_info.K_idx);
521	        }
522	        else {
523	          // Wait until the first split has stored its accumulators. Note that the first split will have
524	          // accumulated a value into the lock potentially greater than one (since the locked value is
525	          // incremented by work_tile_info.k_tile_count below for both the deterministic and non-deterministic)
526	          // cases. For non-deterministic reductions, all that non-first or last splits care about is whether
527	          // the first split has been written, so we only wait while the locked value is less than 1.
528	          BarrierManager::wait_lt(barrier_idx, lock_workspace, barrier_group_thread_idx, lock_idx, 1);
529	        }
530	
531	        // Perform reduction in workspace
532	        BlockStripedReduceT::reduce(reduction_workspace_array, *accumulator_array, barrier_group_thread_idx);
533	      }
534	
535	      // If separate reduction is being performed, each participating stream-K unit increments the barrier
536	      // by only 1. Otherwise, increment by the K tile count that this unit has processed.
537	      uint32_t increment = params.requires_separate_reduction() ? 1 : work_tile_info.k_tile_count;
538	
539	      // Signal our arrival
540	      if (idx_accumulator_mtxs == (num_accumulator_mtxs - 1)) {
541	        BarrierManager::arrive_inc(barrier_idx, lock_workspace, barrier_group_thread_idx, lock_idx, increment);
542	      }
543	    }
544	    else {
545	      // Wait until the preceding split added its accumulators
546	      BarrierManager::wait_eq(barrier_idx, lock_workspace, barrier_group_thread_idx, lock_idx, work_tile_info.K_idx);
547	
548	      // The block computing the final split for the tile adds previously-reduced partials
549	      // to its accumulators and computes the epilogue.
550	      BlockStripedReduceT::load_add(*accumulator_array, reduction_workspace_array, barrier_group_thread_idx);
551	    }
552	  }
