554	  template <class FrgTensorC, class BarrierManager>
555	  CUTLASS_DEVICE
556	  static void
557	  separate_reduction(
558	      FrgTensorC& accumulators,
559	      uint32_t num_barriers,
560	      typename FrgTensorC::value_type* reduction_workspace,
561	      uint32_t thread_idx,
562	      uint64_t num_peers,
563	      uint32_t num_accumulator_mtxs) {
564	    using AccumulatorArrayT = Array<typename FrgTensorC::value_type, size(FrgTensorC{})>;
565	    using BlockStripedReduceT = BlockStripedReduce<BarrierManager::ThreadCount, AccumulatorArrayT>;
566	
567	    AccumulatorArrayT* accumulator_array = reinterpret_cast<AccumulatorArrayT*>(accumulators.data());
568	
569	    plus<AccumulatorArrayT> add_fragments;
570	    uint64_t peer_offset = cute::size<0>(TileShape{}) * cute::size<1>(TileShape{}) * num_accumulator_mtxs;
571	
572	    for (uint64_t i = 0; i < num_peers; ++i) {
573	      // Load peer fragment
574	      AccumulatorArrayT addend_fragment;
575	      auto peer_reduction_workspace = reinterpret_cast<AccumulatorArrayT*>(reduction_workspace + (i * peer_offset));
576	
577	      BlockStripedReduceT::load_add(*accumulator_array, peer_reduction_workspace, thread_idx);
578	    }
579	  }
