581	  // Returns whether the block assigned this work should compute the epilogue for the corresponding
582	  // output tile. For the case of stream-K, this should only occur if the work is marked as the final split.
583	  CUTLASS_HOST_DEVICE
584	  static bool
585	  compute_epilogue(WorkTileInfo const& work_tile_info, Params const& params) {
586	    // `is_final_split` will be set to `true` for the following scenarios, all of which must compute the epilogue:
587	    //  1. The tile is computed in data-parallel mode
588	    //  2. The tile is computed in split-/stream-K mode and this work unit represents the final split of the tile
589	    //  3. The tile is computed in split-/stream-K mode and separate reduction is used, and this is a separate reduction unit
590	    return work_tile_info.is_valid() &&
591	            (work_tile_info.is_final_split(params.divmod_tiles_per_output_tile_.divisor) &&
592	             !params.requires_separate_reduction()) || work_tile_info.is_separate_reduction;
593	  }
594	
595	  // Returns the linearized index of the output tile corresponding to the tile with offset [L, M, K]
596	  CUTLASS_DEVICE
597	  static uint64_t
598	  output_tile_index(Params const& params, WorkTileInfo const& work_tile_info) {
599	    uint64_t linear_idx_in_batch = UnderlyingScheduler::get_linear_idx_from_m_and_n(
600	      work_tile_info.M_idx, work_tile_info.N_idx,
601	      params.divmod_cluster_shape_major_,
602	      params.divmod_cluster_shape_minor_,
603	      params.divmod_cluster_blk_major_,
604	      params.log_swizzle_size_,
605	      params.raster_order_
606	    );
607	
608	    uint64_t tiles_mn = params.divmod_batch_.divisor;
609	    return tiles_mn * work_tile_info.L_idx + linear_idx_in_batch;
610	  }
