1625	// Parameters for SM90 persistent group scheduler (only used for Grouped Gemms)
1626	template<class GroupProblemShape>
1627	struct PersistentTileSchedulerSm90GroupParams {
1628	  using RasterOrder = cutlass::gemm::kernel::detail::RasterOrder;
1629	  using RasterOrderOptions = cutlass::gemm::kernel::detail::RasterOrderOptions;
1630	
1631	  FastDivmodU64Pow2 divmod_cluster_shape_major_{};
1632	  FastDivmodU64Pow2 divmod_cluster_shape_minor_{};
1633	  FastDivmodU64 divmod_cta_shape_m_{};
1634	  FastDivmodU64 divmod_cta_shape_n_{};
1635	
1636	  uint64_t blocks_across_problem_ = 0;
1637	  bool pre_processed_problem_shapes = true;
1638	  int32_t max_swizzle_size_ = 0;
1639	  RasterOrder raster_order_ = RasterOrder::AlongN;
1640	
1641	  GroupProblemShape problem_shapes_;
1642	  GemmCoord cta_shape_;
1643	  GemmCoord cluster_shape_;
1644	
1645	  // Version of initialize that takes in as input the number of CTAs in the M and N and L dimensions.
1646	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
1647	  // for which using CuTe algebra for calculating tile shapes is easiest.
1648	  void
1649	  initialize(
1650	    dim3 problem_blocks,
1651	    GroupProblemShape problem_shapes,
1652	    GemmCoord cta_shape,
1653	    GemmCoord cluster_shape,
1654	    KernelHardwareInfo const& hw_info,
1655	    int max_swizzle_size,
1656	    RasterOrderOptions raster_order_option
1657	  ) {
1658	
1659	    CUTLASS_UNUSED(hw_info);
1660	
1661	    auto problem_blocks_m = round_up(problem_blocks.x, cluster_shape.m());
1662	    auto problem_blocks_n = round_up(problem_blocks.y, cluster_shape.n());
1663	
1664	    RasterOrder raster_order = get_rasterization_order(
1665	      problem_blocks_m,
1666	      problem_blocks_n,
1667	      raster_order_option
1668	    );
1669	
1670	    //
1671	    // Set members
1672	    //
1673	    problem_shapes_ = problem_shapes;
1674	    cta_shape_ = cta_shape;
1675	    cluster_shape_ = cluster_shape;
1676	
1677	    blocks_across_problem_ = problem_blocks.x * problem_blocks.y * problem_blocks.z;
1678	    pre_processed_problem_shapes = problem_shapes.is_host_problem_shape_available();
1679	    max_swizzle_size_ = max_swizzle_size;
1680	    raster_order_ = raster_order;
1681	
1682	    if (raster_order == RasterOrder::AlongN) {
1683	      divmod_cluster_shape_major_ = FastDivmodU64Pow2(cluster_shape.n());
1684	      divmod_cluster_shape_minor_ = FastDivmodU64Pow2(cluster_shape.m());
1685	    }
1686	    else {
1687	      divmod_cluster_shape_major_ = FastDivmodU64Pow2(cluster_shape.m());
1688	      divmod_cluster_shape_minor_ = FastDivmodU64Pow2(cluster_shape.n());
1689	    }
1690	
1691	    divmod_cta_shape_m_ = FastDivmodU64(cta_shape_.m());
1692	    divmod_cta_shape_n_ = FastDivmodU64(cta_shape_.n());
1693	  }
1694	
1695	  // Version of get_tiled_cta_shape_mnl that takes in as input the number of CTAs in the M and N dimensions.
1696	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
1697	  // for which using CuTe algebra for calculating tile shapes is easiest.
1698	  CUTLASS_HOST_DEVICE
1699	  static dim3
1700	  get_tiled_cta_shape_mnl(GemmCoord cluster_shape, uint32_t cta_m, uint32_t cta_n) {
1701	    // Round up to nearest multiple of cluster dim along each mode
1702	    auto problem_blocks_m = ((cta_m + cluster_shape.m() - 1) / cluster_shape.m()) * cluster_shape.m();
1703	    auto problem_blocks_n = ((cta_n + cluster_shape.n() - 1) / cluster_shape.n()) * cluster_shape.n();
1704	
1705	    return {
1706	      static_cast<uint32_t>(cta_m),
1707	      static_cast<uint32_t>(cta_n),
1708	      static_cast<uint32_t>(1) // Only a single batch per group is currently supported
1709	    };
1710	  }
1711	
1712	  // Version of get_grid_shape that takes in as input the number of CTAs in the M and N and L dimensions.
1713	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
1714	  // for which using CuTe algebra for calculating tile shapes is easiest.
1715	  CUTLASS_HOST_DEVICE static
1716	  dim3
1717	  get_grid_shape(
1718	    dim3 problem_blocks,
1719	    GemmCoord cluster_shape,
1720	    KernelHardwareInfo hw_info,
1721	    int max_swizzle_size,
1722	    RasterOrderOptions raster_order_option,
1723	    bool truncate_by_problem_size=true) {
1724	
1725	    int const sm_count = hw_info.sm_count;
1726	    int const max_active_clusters = hw_info.max_active_clusters;
1727	
1728	    auto problem_blocks_m = round_up(problem_blocks.x, cluster_shape.m());
1729	    auto problem_blocks_n = round_up(problem_blocks.y, cluster_shape.n());
1730	
1731	    int problem_blocks_total = problem_blocks_m * problem_blocks_n * problem_blocks.z;
1732	
1733	    RasterOrder raster_order = get_rasterization_order(
1734	      problem_blocks_m,
1735	      problem_blocks_n,
1736	      raster_order_option
1737	    );
1738	
1739	    dim3 launch_grid;
1740	
1741	    if (raster_order == RasterOrder::AlongN) {
1742	      launch_grid = dim3(cluster_shape.m(), 1, 1);
1743	    }
1744	    else {
1745	      launch_grid = dim3(1, cluster_shape.n(), 1);
1746	    }
1747	
1748	    auto possibly_truncate = [&](int x, int y) {
1749	      if (truncate_by_problem_size) {
1750	        return platform::min(x, y);
1751	      }
1752	      else {
1753	        return x;
1754	      }
1755	    };
1756	
1757	    // The else path is generic, however, we can avoid some divs if we know cluster size is 1
1758	    auto cluster_size = cluster_shape.m() * cluster_shape.n();
1759	    if (cluster_size == 1) {
1760	      if (raster_order == RasterOrder::AlongN) {
1761	        launch_grid.y = possibly_truncate(sm_count, problem_blocks_total);
1762	      }
1763	      else {
1764	        launch_grid.x = possibly_truncate(sm_count, problem_blocks_total);
1765	      }
1766	    }
1767	    // In case the maximum number of clusters that could co-exist on the target device is
1768	    // already calculated using cudaOccupancyMaxActiveClusters
1769	    else if (max_active_clusters != 0 && max_active_clusters * cluster_size <= sm_count) {
1770	      if (raster_order == RasterOrder::AlongN) {
1771	        launch_grid.y = max_active_clusters * cluster_shape.n();
1772	      }
1773	      else {
1774	        launch_grid.x = max_active_clusters * cluster_shape.m();
1775	      }
1776	      CUTLASS_TRACE_HOST("get_grid_shape(): Proposed GridDims by the scheduler using cudaOccupancyMaxActiveClusters = "
1777	          "(" << launch_grid.x << ", " << launch_grid.y << ", " << launch_grid.z << ")\n");
1778	    }
1779	    else {
1780	      // Optimal grid size calculation is based on
1781	      // GH100: 8 GPCs, 72 TPCs (9 TPCs/GPC), 2 SMs/TPC, 144 SMs per full GPU
1782	      // Hence, maximum SMs per GPC = 18
1783	      constexpr int max_sm_per_gpc = 18;
1784	      int cta_per_device = get_max_cta_occupancy(max_sm_per_gpc, cluster_shape, sm_count);
1785	
1786	      if (raster_order == RasterOrder::AlongN) {
1787	        launch_grid.y = possibly_truncate(
1788	            cta_per_device       / cluster_shape.m(),
1789	            problem_blocks_total / cluster_shape.m());
1790	      }
1791	      else {
1792	        launch_grid.x = possibly_truncate(
1793	            cta_per_device       / cluster_shape.n(),
1794	            problem_blocks_total / cluster_shape.n());
1795	      }
1796	      CUTLASS_TRACE_HOST("get_grid_shape(): Proposed GridDims by the scheduler using heuristics = "
1797	          "(" << launch_grid.x << ", " << launch_grid.y << ", " << launch_grid.z << ")\n");
1798	    }
1799	    return launch_grid;
1800	  }
1801	
1802	  CUTLASS_HOST_DEVICE
1803	  static RasterOrder
1804	  get_rasterization_order(
1805	    uint32_t tiles_m,
1806	    uint32_t tiles_n,
1807	    RasterOrderOptions raster_order_option
1808	  ) {
1809	
1810	    if (raster_order_option == RasterOrderOptions::Heuristic) {
1811	      if (tiles_n > tiles_m) {
1812	        return RasterOrder::AlongM;
1813	      }
1814	      else {
1815	        return RasterOrder::AlongN;
1816	      }
1817	    }
1818	    else {
1819	      switch (raster_order_option) {
1820	        case RasterOrderOptions::AlongN:
1821	          return RasterOrder::AlongN;
1822	          break;
1823	        default:
1824	          return RasterOrder::AlongM;
1825	      }
1826	    }
1827	  }
1828	};
