1837	// Parameters for SM100 persistent tile scheduler
1838	struct PersistentTileSchedulerSm100Params {
1839	
1840	  using UnderlyingParams = PersistentTileSchedulerSm90Params;
1841	
1842	  using RasterOrder = UnderlyingParams::RasterOrder;
1843	  using RasterOrderOptions = UnderlyingParams::RasterOrderOptions;
1844	
1845	  uint32_t problem_tiles_m_ = 0;
1846	  uint32_t problem_tiles_n_ = 0;
1847	  uint32_t problem_tiles_l_ = 0;
1848	  FastDivmod divmod_cluster_shape_m_{};
1849	  FastDivmod divmod_cluster_shape_n_{};
1850	  FastDivmod divmod_swizzle_size_{};
1851	  RasterOrder raster_order_ = RasterOrder::AlongM;
1852	  int32_t log_swizzle_size_ = 0;
1853	  // Initializes members. This variant of the method should only be used when
1854	  // problem_shape and tile_shape contain modes of only rank 1.
1855	  void
1856	  initialize(
1857	    BatchedGemmCoord problem_shape,
1858	    GemmCoord tile_shape,
1859	    GemmCoord cluster_shape,
1860	    KernelHardwareInfo const& hw_info,
1861	    int max_swizzle_size,
1862	    RasterOrderOptions raster_order_option
1863	  ) {
1864	    dim3 problem_blocks = UnderlyingParams::get_tiled_cta_shape_mnl(problem_shape, tile_shape, cluster_shape);
1865	    initialize(
1866	      problem_blocks,
1867	      cluster_shape,
1868	      hw_info,
1869	      max_swizzle_size,
1870	      raster_order_option
1871	    );
1872	  }
1873	
1874	  void initialize_swizzle(
1875	      dim3 problem_blocks,
1876	      GemmCoord cluster_shape,
1877	      KernelHardwareInfo const& hw_info,
1878	      int max_swizzle_size,
1879	      RasterOrderOptions raster_order_option) {
1880	
1881	    raster_order_ = UnderlyingParams::get_rasterization_order(problem_tiles_m_, problem_tiles_n_, raster_order_option);
1882	    if (raster_order_option == RasterOrderOptions::Heuristic && raster_order_ == RasterOrder::AlongN) {
1883	      // The current implementation of AlongN rasterization for B100 requires swapping the number of clusters along the
1884	      // X and Y dimensions of the grid. However, since the grid Y dimension has a smaller range of allowed values
1885	      // than the grid X dimension, we must check whether the swapped grid would exceed the grid Y limit. If the
1886	      // swapped grid would exceed this limit, simply rever to AlongM mode.
1887	      //
1888	      // Overflow in the swapped X dimension is not possible. At worst, there will be ((1 << 16) - 1) clusters
1889	      // along the original Y dimension of the grid. Even if the cluster M mode is 16, the new grid X value
1890	      // will be at most ((1 << 16) - 1) * 16, which is less than the grid X limit of ((1 << 31) - 1).
1891	      uint32_t new_grid_y = problem_tiles_m_ * static_cast<uint32_t>(cluster_shape.n());
1892	
1893	      if (new_grid_y > (1 << 16) - 1) {
1894	        raster_order_ = RasterOrder::AlongM;
1895	      }
1896	    }
1897	
1898	    if (max_swizzle_size <= 1) {
1899	      // Set divisors directly to be zero to mark as unused
1900	      divmod_swizzle_size_.divisor = 0;
1901	    }
1902	    else {
1903	      divmod_swizzle_size_ = FastDivmod(max_swizzle_size);
1904	    }
1905	  }
1906	
1907	  // Version of initialize that takes in as input the number of CTAs in the M and N and L dimensions.
1908	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
1909	  // for which using CuTe algebra for calculating tile shapes is easiest.
1910	  void
1911	  initialize(
1912	      dim3 problem_blocks,
1913	      GemmCoord cluster_shape,
1914	      KernelHardwareInfo const& hw_info,
1915	      int max_swizzle_size,
1916	      RasterOrderOptions raster_order_option
1917	  ) {
1918	
1919	    // Cluster counters in m, n and l dimensions of the problem tiles
1920	    problem_tiles_m_ = problem_blocks.x / cluster_shape.m();
1921	    problem_tiles_n_ = problem_blocks.y / cluster_shape.n();
1922	    problem_tiles_l_ = problem_blocks.z;
1923	    divmod_cluster_shape_m_ = FastDivmod(cluster_shape.m());
1924	    divmod_cluster_shape_n_ = FastDivmod(cluster_shape.n());
1925	
1926	    initialize_swizzle(problem_blocks, cluster_shape, hw_info, max_swizzle_size, raster_order_option);
1927	  }
1928	
1929	  // Given the inputs, computes the physical grid we should launch.
1930	  // This variant of the method should only be used when
1931	  // problem_shape and tile_shape contain modes of only rank 1.
1932	  CUTLASS_HOST_DEVICE static
1933	  dim3
1934	  get_grid_shape(
1935	    BatchedGemmCoord problem_shape,
1936	    GemmCoord cta_shape,
1937	    GemmCoord cluster_shape,
1938	    KernelHardwareInfo hw_info,
1939	    int max_swizzle_size,
1940	    RasterOrderOptions raster_order_option
1941	  ) {
1942	
1943	    CUTLASS_UNUSED(cluster_shape);
1944	    CUTLASS_UNUSED(hw_info);
1945	    CUTLASS_UNUSED(max_swizzle_size);
1946	    CUTLASS_UNUSED(raster_order_option);
1947	
1948	    return get_tiled_cta_shape_mnl(problem_shape, cta_shape, cluster_shape);
1949	  }
1950	
1951	  // Get the number of CTA tiles in this problem. This variant of the method should only be used when
1952	  // problem_shape and tile_shape contain modes of only rank 1.
1953	  CUTLASS_HOST_DEVICE
1954	  static dim3
1955	  get_tiled_cta_shape_mnl(
1956	    BatchedGemmCoord problem_shape,
