1959	
1960	    return UnderlyingParams::get_tiled_cta_shape_mnl(problem_shape, cta_shape, cluster_shape);
1961	  }
1962	
1963	  // Get the amount of scratch workspace needed for the kernel. This variant of the method should only be used when
1964	  // problem_shape and tile_shape contain modes of only rank 1.
1965	  static size_t
1966	  get_workspace_size(
1967	    BatchedGemmCoord problem_shape,
1968	    GemmCoord tile_shape,
1969	    GemmCoord cluster_shape,
1970	    KernelHardwareInfo const& hw_info,
1971	    int max_swizzle,
1972	    RasterOrderOptions raster_order_option
1973	  ) {
1974	    dim3 problem_blocks = get_tiled_cta_shape_mnl(problem_shape, tile_shape, cluster_shape);
1975	    return get_workspace_size(
1976	      problem_blocks,
1977	      cluster_shape,
1978	      hw_info,
1979	      max_swizzle,
1980	      raster_order_option
1981	    );
1982	  }
1983	
1984	  // Version of get_workspace_size that takes in as input the number of CTAs in the M and N dimensions.
1985	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
1986	  // for which using CuTe algebra for calculating tile shapes is easiest.
1987	  static size_t
1988	  get_workspace_size(
1989	    dim3 problem_blocks,
1990	    GemmCoord cluster_shape,
1991	    KernelHardwareInfo const& hw_info,
