2084	    int splits,
2085	    int max_swizzle_size,
2086	    RasterOrderOptions raster_order_option,
2087	    ReductionMode reduction_mode,
2088	    DecompositionMode decomposition_mode,
2089	    void* workspace,
2090	    uint32_t ktile_start_alignment_count = 1u
2091	  ) {
2092	    dim3 problem_blocks = get_tiled_cta_shape_mnl(problem_shape, tile_shape, cluster_shape);
2093	
2094	    // Number of k tiles in each output tile
2095	    uint32_t k_tiles_per_output_tile = (problem_shape.k() + tile_shape.k() - 1) / tile_shape.k();
2096	
2097	    initialize(
2098	      problem_blocks,
2099	      k_tiles_per_output_tile,
2100	      cluster_shape,
2101	      hw_info,
2102	      splits,
2103	      max_swizzle_size,
2104	      raster_order_option,
2105	      reduction_mode,
2106	      decomposition_mode,
2107	      workspace,
2108	      ktile_start_alignment_count
2109	    );
2110	  }
2111	
2112	  // Version of initialize that takes in as input the number of CTAs in the M and N and L dimensions.
2113	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
2114	  // for which using CuTe algebra for calculating tile shapes is easiest.
2115	  void
2116	  initialize(
