2157	  // Get the number of CTA tiles in this problem.
2158	  CUTLASS_HOST_DEVICE
2159	  static dim3
2160	  get_tiled_cta_shape_mnl(
2161	    BatchedGemmCoord problem_shape,
2162	    GemmCoord cta_shape,
2163	    GemmCoord cluster_shape) {
2164	
2165	    return UnderlyingParams::get_tiled_cta_shape_mnl(problem_shape, cta_shape, cluster_shape);
2166	  }
2167	
2168	  // Given the inputs, computes the physical grid we should launch.
2169	  // This variant of the method should only be used when
2170	  // problem_shape and tile_shape contain modes of only rank 1.
2171	  CUTLASS_HOST_DEVICE
2172	  dim3
2173	  get_grid_shape(BatchedGemmCoord problem_shape, GemmCoord cta_shape, GemmCoord cluster_shape) const {
2174	    dim3 problem_blocks = get_tiled_cta_shape_mnl(problem_shape, cta_shape, cluster_shape);
2175	
2176	    return get_grid_shape(problem_blocks, cluster_shape);
2177	  }
2178	
2179	  // Version of get_grid_shape that takes in as input the number of CTAs in the M and N and L dimensions.
2180	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
2181	  // for which using CuTe algebra for calculating tile shapes is easiest.
2182	  CUTLASS_HOST_DEVICE
2183	  dim3
2184	  get_grid_shape(dim3 problem_blocks, GemmCoord cluster_shape) const {
2185	    if (sk_params_.sk_units_ > 0) {
2186	      // For stream-K cases, we would, ideally, launch a linear grid of size `sk_params_.units_per_problem_`.
2187	      // However doing so raises two potential issues:
2188	      //   (a) the total number of tiles in the kernel may exceed the amount that can fit in a single
2189	      //       returned value of a CLC query
2190	      //   (b) the launched grid would not respect cluster-size divisibility requirements
2191	      //
2192	      // To circumvent these issues, we must distribute the `sk_params_.units_per_problem_` units of work
2193	      // across the X, Y, and Z dimensions of the grid, while ensuring that the X and Y dimensions are
2194	      // divisible by cluster size (we ignore Z, as all CUTLASS kernels currently use a cluster shape
2195	      // of 1 in the Z dimension).
2196	      //
2197	      // For convenience, we launch this as "waves" of `sk_params_.sk_units_` CTAs, with the wave count being
2198	      // the Z dimension of the grid, and the `sk_params_.sk_units_` CTAs per wave being distributed across
2199	      // the X and Y dimensions of the grid in a way that alingns with cluster divisibility requirements.
2200	      //
2201	      // Thus, the grid that is launched looks like:
2202	      //   grid = dim3(sk_units_ / cluster.y, cluster.y, waves)
2203	      //
2204	      // We place sk_units_ / cluster.y in the X dimension of the grid because the CLC query feature
2205	      // allocates more bits for the X index values returned in the query.
2206	      //
2207	
2208	      // For most cases, `sk_params_.sk_units_` will equal the number of available SMs, so this grid will
2209	      // naturally represent waves in the true hardware sense.
2210	      //
2211	      // However, there are some corner cases in which fewer stream-K units are used than the full SM count
2212	      // (e.g., if using the full SM count would result in stream-K units that are assigned fewer than the
2213	      // minimum number of K tile iterations). In these cases, `sk_params_.units_per_problem_` may not be
2214	      // divisible by `sk_params_.sk_units_`, since any data-parallel work performed alongside stream-K
2215	      // work is always done in terms of waves of CTAs of number equal to the number of available SMs.
2216	      // Therefore, we take the ceiling of the division when determining wave count, and allow the underlying
2217	      // stream-K scheduler to determine which indices are in bounds.
2218	      uint32_t waves = static_cast<uint32_t>(
2219	        (sk_params_.units_per_problem_ + sk_params_.sk_units_ - 1) / sk_params_.sk_units_);
2220	
2221	      return dim3(
2222	        sk_params_.sk_units_ / cluster_shape.n(),
2223	        cluster_shape.n(),
2224	        waves
2225	      );
2226	    }
2227	    else {
2228	      // Grid launch for data-parallel and basic split-K decomposition. When data-parallel
2229	      // mode is used, params.sk_params_.splits = 1.
2230	      return dim3(problem_blocks.x, problem_blocks.y, problem_blocks.z * sk_params_.divmod_splits_.divisor);
2231	    }
2232	  }
