2416	// Parameters for SM100 persistent group scheduler (only used for Grouped Gemms)
2417	template<class GroupProblemShape>
2418	struct PersistentTileSchedulerSm100GroupParams {
2419	
2420	  using UnderlyingSm90Params = PersistentTileSchedulerSm90GroupParams<GroupProblemShape>;
2421	  using RasterOrder = cutlass::gemm::kernel::detail::RasterOrder;
2422	  using RasterOrderOptions = cutlass::gemm::kernel::detail::RasterOrderOptions;
2423	
2424	  UnderlyingSm90Params params_sm90_{};
2425	
2426	  // Version of initialize that takes in as input the number of CTAs in the M and N and L dimensions.
2427	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
2428	  // for which using CuTe algebra for calculating tile shapes is easiest.
2429	  void
2430	  initialize(
2431	    dim3 problem_blocks,
2432	    GroupProblemShape problem_shapes,
2433	    GemmCoord cta_shape,
2434	    GemmCoord cluster_shape,
2435	    KernelHardwareInfo const& hw_info,
2436	    int max_swizzle_size,
2437	    RasterOrderOptions raster_order_option
2438	  ) {
2439	
2440	    params_sm90_.initialize(
2441	      problem_blocks,
2442	      problem_shapes,
2443	      cta_shape,
2444	      cluster_shape,
2445	      hw_info,
2446	      max_swizzle_size,
2447	      raster_order_option
2448	    );
2449	  }
2450	
2451	  // Version of get_tiled_cta_shape_mnl that takes in as input the number of CTAs in the M and N dimensions.
2452	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
2453	  // for which using CuTe algebra for calculating tile shapes is easiest.
2454	  CUTLASS_HOST_DEVICE
2455	  static dim3
2456	  get_tiled_cta_shape_mnl(GemmCoord cluster_shape, uint32_t cta_m, uint32_t cta_n) {
2457	    return UnderlyingSm90Params::get_tiled_cta_shape_mnl(cluster_shape, cta_m, cta_n);
2458	  }
2459	
2460	  // Version of get_grid_shape that takes in as input the number of CTAs in the M and N and L dimensions.
2461	  // This is useful for calculating the tiled shape when a mode of problem and/or CTA shape has rank > 1,
2462	  // for which using CuTe algebra for calculating tile shapes is easiest.
2463	  CUTLASS_HOST_DEVICE static
2464	  dim3
2465	  get_grid_shape(
2466	    dim3 problem_blocks,
2467	    GemmCoord cluster_shape,
2468	    KernelHardwareInfo hw_info,
2469	    int max_swizzle_size,
2470	    RasterOrderOptions raster_order_option,
2471	    bool truncate_by_problem_size = true,
2472	    bool is_static_cluster_shape = false) {
2473	
2474	    int const sm_count = hw_info.sm_count;
2475	    int const max_active_clusters = hw_info.max_active_clusters;
2476	
2477	    auto problem_blocks_m = round_up(problem_blocks.x, cluster_shape.m());
2478	    auto problem_blocks_n = round_up(problem_blocks.y, cluster_shape.n());
2479	
2480	    int problem_blocks_total = problem_blocks_m * problem_blocks_n * problem_blocks.z;
2481	
2482	    RasterOrder raster_order = get_rasterization_order(
2483	      problem_blocks_m,
2484	      problem_blocks_n,
2485	      raster_order_option
2486	    );
2487	
2488	    dim3 launch_grid;
2489	
2490	    if (raster_order == RasterOrder::AlongN) {
2491	      launch_grid = dim3(cluster_shape.m(), 1, 1);
2492	    }
2493	    else {
2494	      launch_grid = dim3(1, cluster_shape.n(), 1);
2495	    }
2496	
2497	    auto possibly_truncate = [&](int x, int y) {
2498	      if (truncate_by_problem_size) {
2499	        return platform::min(x, y);
2500	      }
2501	      else {
2502	        return x;
2503	      }
2504	    };
2505	    
2506	    if (is_static_cluster_shape) {
2507	      // The else path is generic, however, we can avoid some divs if we know cluster size is 1
2508	      auto cluster_size = cluster_shape.m() * cluster_shape.n();
2509	      if (cluster_size == 1) {
2510	        if (raster_order == RasterOrder::AlongN) {
2511	          launch_grid.y = possibly_truncate(sm_count, problem_blocks_total);
2512	        }
2513	        else {
2514	          launch_grid.x = possibly_truncate(sm_count, problem_blocks_total);
2515	        }
2516	      }
2517	      // In case the maximum number of clusters that could co-exist on the target device is
2518	      // already calculated using cudaOccupancyMaxActiveClusters
2519	      else if (max_active_clusters != 0 && max_active_clusters * cluster_size <= sm_count) {
2520	        if (raster_order == RasterOrder::AlongN) {
2521	          launch_grid.y = max_active_clusters * cluster_shape.n();
2522	        }
2523	        else {
2524	          launch_grid.x = max_active_clusters * cluster_shape.m();
2525	        }
2526	        CUTLASS_TRACE_HOST("get_grid_shape(): Proposed GridDims by the scheduler using cudaOccupancyMaxActiveClusters = "
2527	            "(" << launch_grid.x << ", " << launch_grid.y << ", " << launch_grid.z << ")\n");
2528	      }
2529	      else {
2530	        constexpr int max_sm_per_gpc = 20;
2531	        int cta_per_device = get_max_cta_occupancy(max_sm_per_gpc, cluster_shape, sm_count);
2532	        if (raster_order == RasterOrder::AlongN) {
2533	          launch_grid.y = possibly_truncate(
2534	              cta_per_device       / cluster_shape.m(),
2535	              problem_blocks_total / cluster_shape.m());
2536	        }
2537	        else {
2538	          launch_grid.x = possibly_truncate(
2539	              cta_per_device       / cluster_shape.n(),
2540	              problem_blocks_total / cluster_shape.n());
2541	        }
2542	        CUTLASS_TRACE_HOST("get_grid_shape(): Proposed GridDims by the scheduler using heuristics = "
2543	            "(" << launch_grid.x << ", " << launch_grid.y << ", " << launch_grid.z << ")\n");
2544	      }
2545	    }
2546	    else {
2547	      // With preferred clusters, we can launch the largest possible persistent grid (rounded up to cluster dims) 
2548	      if (raster_order == RasterOrder::AlongN) {
2549	        launch_grid.y = ((possibly_truncate(sm_count, problem_blocks_total) / cluster_shape.m()) / cluster_shape.n()) * cluster_shape.n();
2550	      }
2551	      else {
2552	        launch_grid.x = ((possibly_truncate(sm_count, problem_blocks_total) / cluster_shape.n()) / cluster_shape.m()) * cluster_shape.m();
2553	      }
2554	      CUTLASS_TRACE_HOST("get_grid_shape(): Proposed GridDims by the scheduler using preferred clusters = "
2555	          "(" << launch_grid.x << ", " << launch_grid.y << ", " << launch_grid.z << ")\n");
2556	    }
2557	    return launch_grid;
2558	  }
2559	
2560	  CUTLASS_HOST_DEVICE
2561	  static RasterOrder
2562	  get_rasterization_order(
2563	    uint32_t tiles_m,
2564	    uint32_t tiles_n,
2565	    RasterOrderOptions raster_order_option
2566	  ) {
2567	    return UnderlyingSm90Params::get_rasterization_order(tiles_m, tiles_n, raster_order_option);
2568	  }
2569	};
