762	  CUTLASS_DEVICE
763	  static uint32_t
764	  get_current_work_iter_start_possible_update_work_tile_k_remaining(
765	    Params const& params,
766	    uint64_t linear_idx,
767	    WorkTileInfo& work_tile_info) {
768	    // In the CUTLASS 2.x implementation of stream K, stream-K work is assigned to each stream-K
769	    // threadblock individually. For the most part, the set of K iterations corresponding to stream-K
770	    // work was divided amongst stream-K threadblocks, and a threadblock determined which tile
771	    // it would compute a (potentially-partial) output tile for based on the space of k iterations
772	    // assigned to it. This often results in stream-K threadblocks processing tiles with different
773	    // offsets in the K dimension from one another. This can reduce locality, but is lmitied to the
774	    // (generally few) waves of threadblocks assigned to compute stream-K work.
775	    //
776	    // With the introduction of threadblock clusters, there is additional benefit to maintaining
777	    // locality in the K dimension: shared portions of operands can be multicasted to threadblocks
778	    // within a cluster. Thus, we would like to ensure that the assignment of stream-K work to
779	    // threadblocks respects the ability to perform multicasting.
780	    //
781	    // To do so, we divide up the linearized stream-K units into clusters and share the same K
782	    // offsets for work within clusters.
783	    uint64_t cluster_linear_work_idx = params.div_cluster_size(linear_idx);
784	
785	    uint64_t group_idx;
786	    params.divmod_sk_groups_(cluster_linear_work_idx, group_idx, cluster_linear_work_idx);
787	
788	    // Determine whether we are in a "big group" that will process an additional
789	    // stream-K cluster tile.
790	    uint64_t sk_cluster_tiles = params.div_cluster_size(params.sk_tiles_);
791	    uint64_t sk_cluster_tiles_in_group = params.divmod_sk_groups_.divide(sk_cluster_tiles);
792	    if (group_idx < params.big_groups_) {
793	      ++sk_cluster_tiles_in_group;
794	    }
795	
796	    // Determine whether we are in a "big unit" within the group, that will process
797	    // an additional K chunk in the group.
798	    uint64_t sk_tiles_in_group = sk_cluster_tiles_in_group * params.get_cluster_size();
799	    uint64_t k_tiles_in_group = sk_tiles_in_group * params.divmod_tiles_per_output_tile_.divisor;
800	    uint64_t k_tiles_per_unit_in_group = params.divmod_sk_units_per_group_.divide(k_tiles_in_group);
801	    uint64_t big_units_in_group = params.div_cluster_size(
802	      k_tiles_in_group - (k_tiles_per_unit_in_group * params.divmod_sk_units_per_group_.divisor));
803	
804	    uint64_t split;
805	    params.divmod_clusters_mnl_(split, cluster_linear_work_idx, cluster_linear_work_idx);
806	
807	    bool is_split_k = params.divmod_splits_.divisor > 1;
808	    uint64_t big_unit_cmp_lhs = is_split_k ? split : cluster_linear_work_idx;
809	    uint64_t big_unit_cmp_rhs = is_split_k ? params.big_units_ : big_units_in_group;
810	    uint64_t linear_idx_mult = is_split_k ? params.divmod_tiles_per_output_tile_.divisor : k_tiles_per_unit_in_group;
811	    uint64_t k_tiles_per_split = is_split_k ? params.divmod_k_tiles_per_sk_unit_.divisor : k_tiles_per_unit_in_group;
812	
813	    // Determine the starting k iteration computed by this stream-K work unit
814	    uint32_t unit_iter_start = (linear_idx_mult * cluster_linear_work_idx) +
815	                               (k_tiles_per_split * split);
816	
817	    // Adjust the starting position and number of k iterations for "big units," which
818	    // compute one extra iteration. If there are any big units, they will be the first
819	    // in the linearized ID space.
820	    auto k_tiles_in_my_split = k_tiles_per_split;
821	    if (big_unit_cmp_lhs < big_unit_cmp_rhs) {
822	      // Since the "big units" are the first units in the linearized ID space, each
823	      // of the units preceding this big unit computed one extra iteration. Thus,
824	      // we must offset our start iteration by the number of units that precede
825	      // the current unit in the linearized ID space.
826	      unit_iter_start += big_unit_cmp_lhs;
827	      ++k_tiles_in_my_split;
828	    }
829	    else {
830	      // Increment by one for each of the big clusters (since all big units precede this unit)
831	      unit_iter_start += big_unit_cmp_rhs;
832	    }
833	    if (!is_split_k) {
834	      // Adjust the unit starting position and number of tiles to avoid
835	      // computing splits of size less than min_iters_per_sk_unit_
836	      int unused, start_tile_k_tile;
837	      params.divmod_tiles_per_output_tile_(unused, start_tile_k_tile, unit_iter_start);
838	      if (start_tile_k_tile < Params::min_iters_per_sk_unit_) {
839	        // Starting K tile is in range [0, Params::min_iters_per_sk_unit_), which means that another
840	        // stream-K unit will be computing a split with fewer than Params::min_iters_per_sk_unit_ K tiles.
841	        // Adjust our work to take over these K tiles.
842	        unit_iter_start -= start_tile_k_tile;
843	        k_tiles_in_my_split += start_tile_k_tile;
844	      }
845	      else if (start_tile_k_tile > (params.divmod_tiles_per_output_tile_.divisor - Params::min_iters_per_sk_unit_)) {
846	        // Starting K tile is within the final Params::min_iters_per_sk_unit_ K tiles of some output tile,
847	        // which means that this unit will compute a split with fewer than Params::min_iters_per_sk_unit_ K tiles.
848	        // Adjust our work to shed these K tiles to a neighboring stream-K unit that will compute more consecutive K tiles.
849	        auto adjustment_tiles = (params.divmod_tiles_per_output_tile_.divisor - start_tile_k_tile);
850	        unit_iter_start += adjustment_tiles;
851	        k_tiles_in_my_split -= adjustment_tiles;
852	      }
853	      else if (params.ktile_start_alignment_count_ == 2 && start_tile_k_tile % 2 != 0) {
854	        // ktile for each SM start from even number
855	        // If start from odd number ktile within the output tile
856	        //    now start at the ktile one before my initial ktile start (take one ktile from prev sm)
857	        // if end on odd number ktile within the output tile
858	        //    now end at ktile that one before my ktile end (give one ktile to next sm)
859	        unit_iter_start -= 1;
860	        k_tiles_in_my_split += 1;
861	      }
862	    }
863	    if (work_tile_info.k_tile_count == 0) {
864	      // This is a new unit
865	
866	      if (!is_split_k) {
867	        //
868	        // Adjust the unit ending position and number of tiles to avoid
869	        // computing splits of size less than min_iters_per_sk_unit_
870	        //
871	
872	        // Begin by assuming that no adjustment is needed
873	        auto initial_unit_iter_end = unit_iter_start + k_tiles_in_my_split;
874	
875	        int unused, end_tile_k_tile;
876	        params.divmod_tiles_per_output_tile_(unused, end_tile_k_tile, initial_unit_iter_end);
877	
878	        if (end_tile_k_tile < Params::min_iters_per_sk_unit_) {
879	          // Ending K tile is within the first Params::min_iters_per_sk_unit_ K tiles of some output tile,
880	          // which means that this unit will compute a split with fewer than Params::min_iters_per_sk_unit_ K tiles.
881	          // Adjust our work to shed these K tiles to a neighboring stream-K unit that will compute more consecutive K tiles.
882	          k_tiles_in_my_split -= end_tile_k_tile;
883	        }
884	        else if (end_tile_k_tile > (params.divmod_tiles_per_output_tile_.divisor - Params::min_iters_per_sk_unit_)) {
885	          // Ending K tile is within the final Params::min_iters_per_sk_unit_ K tiles of some output tile,
886	          // which means that some other unit will compute a split with fewer than Params::min_iters_per_sk_unit_ K tiles.
887	          // Adjust our work to take on these K tiles.
888	          k_tiles_in_my_split += (params.divmod_tiles_per_output_tile_.divisor - end_tile_k_tile);
889	        }
890	        else if (params.ktile_start_alignment_count_ == 2 && end_tile_k_tile % 2 != 0) {
891	          // ktile for each SM start from even number
892	          // If start from odd number ktile within the output tile
893	          //    now start at the ktile one before my initial ktile start (take one ktile from prev sm)
894	          // If end on odd number ktile within the output tile,
895	          //    now end at ktile that one before my ktile end (give one ktile to next sm)
896	          k_tiles_in_my_split -= 1;
897	        }
898	      }
899	
900	      work_tile_info.k_tile_remaining = k_tiles_in_my_split;
901	    }
902	    return unit_iter_start;
903	  }
