905	  // Update output tile index given existing remaining k tiles of current work tile.
906	  CUTLASS_DEVICE
907	  static uint64_t update_output_tile_id_and_work_tile_k(
908	    Params const& params,
909	    WorkTileInfo& work_tile_info,
910	    uint64_t linear_idx,
911	    uint32_t unit_iter_start,
912	    uint64_t cta_m_in_cluster,
913	    uint64_t cta_n_in_cluster) {
914	    // we divide up the linearized stream-K units into clusters and share the same K
915	    // offsets for work within clusters.
916	    uint64_t cluster_linear_work_idx = params.div_cluster_size(linear_idx);
917	
918	    uint64_t unused, group_idx;
919	    params.divmod_sk_groups_(unused, group_idx, cluster_linear_work_idx);
920	
921	    uint32_t unit_iter_end = unit_iter_start + work_tile_info.k_tile_remaining - 1;
922	
923	    // Find the output tile corresponding to the final k tile covered by this
924	    // work unit. Stream-K work units will work backwards in terms of the tiles they
925	    // are responsible computing. This is beneficial because the final (partial)
926	    // tile computed by a stream-K block is typically the beginning of the output
927	    // tile, while the beginning (partial) tile is typically the ending of another
928	    // output tile. Since ending portions of an output tile must reduce across
929	    // other work units computing portions of that output tile, it is preferable
930	    // for them to be computed later, so as to reduce the likelihood of blocking
931	    // on other work.
932	
933	    auto output_tile_id_in_group = params.divmod_tiles_per_output_tile_.divide(unit_iter_end);
934	    uint32_t output_tile_iter_start = output_tile_id_in_group * params.divmod_tiles_per_output_tile_.divisor;
935	    uint32_t output_tile_iter_end = output_tile_iter_start + params.divmod_tiles_per_output_tile_.divisor;
936	
937	    // Convert the output tile from the linearized space within each group to the
938	    // overall linearized space.
939	    uint64_t output_tile_id = (output_tile_id_in_group * params.divmod_sk_groups_.divisor) + group_idx;
940	
941	    // Bring the linearized tile ID back into the space of tiles, rather than clusters
942	    output_tile_id *= params.get_cluster_size();
943	
944	    // The final linearized tile ID is in units of the cluster dimension over which we rasterize.
945	    if (params.raster_order_ == RasterOrder::AlongN) {
946	      output_tile_id += cta_n_in_cluster * params.divmod_cluster_shape_minor_.divisor;
947	    }
948	    else {
949	      output_tile_id += cta_m_in_cluster * params.divmod_cluster_shape_minor_.divisor;
950	    }
951	    // The unit's starting k iteration in the current tile is either the starting
952	    // iteration for the tile as a whole, or the starting k iteration for the unit
953	    // as a whole (if the latter is greater than the former).
954	    uint32_t tile_iter_start = max(output_tile_iter_start, unit_iter_start);
955	
956	    // Similarly, the unit's ending k iteration (exclusive) is either the end of
957	    // the current tile it is assigned, or the ending iteration of the unit as a whole
958	    // (if the latter is less than the former).
959	    uint32_t tile_iter_end = min(output_tile_iter_end, unit_iter_end + 1);
960	
961	    // Set the k offset to be the starting k tile for this output tile
962	    work_tile_info.K_idx = static_cast<int32_t>(tile_iter_start - output_tile_iter_start);
963	    work_tile_info.k_tile_count = tile_iter_end - tile_iter_start;
964	
965	    return output_tile_id;
966	  }
